// https://leetcode.com/problems/check-if-strings-can-be-made-equal-with-operations-ii/

#include <bits/stdc++.h>
using namespace std;
using namespace std::chrono;
#define ll long long
#define endl '\n'

bool checkStrings(string s1, string s2) {
        vector<int> a(26,0), b(26,0);
        for(int i=0;i<s1.length();++i){
            if(i%2==0)
                ++a[s1[i]-'a'];
            else
                ++b[s1[i]-'a'];
        }
        for(int i=0;i<s2.length();++i){
            if(i%2==0)
                --a[s2[i]-'a'];
            else
                --b[s2[i]-'a'];
        }

        for(int i=0;i<26;++i){
            if(a[i] != 0 || b[i] != 0)
                return false;
        }
        return true;
    }

bool checkStrings1(string s1, string s2) {
    if (s1.length() != s2.length()) {
        return false;
    }

    int counts[256] = {0};

    for (int i = 0; i < s1.length(); i++) {
        int offset = (i & 1) << 7;
        counts[offset + s1[i]]++;
        counts[offset + s2[i]]--;
    }

    for (int i = 0; i < 256; i++) {
        if (counts[i] != 0) {
            return false;
        }
    }

    return true;
}

bool checkStrings2(string s1, string s2) {
    vector<int> odd(26);
    vector<int> even(26);
    for(int i=0; i<s1.size(); i++){
        if(i&1){
            odd[s1[i]-'a']++;
        }
        else{
            even[s1[i]-'a']++;
        }
    }
    for(int i=0; i<s2.size(); i++){
        if(i&1){
            odd[s2[i]-'a']--;
        }
        else{
            even[s2[i]-'a']--;
        }
    }
    for(const int &i: odd){
        if(i!=0) return false;
    }
    for(const int &i: even){
        if(i!=0) return false;
    }
    return true;
}

