bool checkStrings4(string s1, string s2) {
    std::vector<int> odds(26);
    std::vector<int> evens(26);
    bool even = true;
    for (int i = 0; i < s1.size(); i++) {
        even = !even;
        if (even) {
            evens[s1[i] - 'a']++;
            evens[s2[i] - 'a']--;
        } else {
            odds[s1[i] - 'a']++;
            odds[s2[i] - 'a']--;
        }
    }
    for (int i = 0; i < odds.size(); i++) {
        if (odds[i] != 0 || evens[i] != 0) {
            return false;
        }
    }
    return true;
}

bool checkStrings5(string s1, string s2) {
    bool ans=false;
    int earr1[26]={0};
    int oarr1[26]={0};
    int earr2[26]={0};
    int oarr2[26]={0};
    int n=s1.length();
    for(int i=0;i<n;i++)
    {
        if(i%2==0)
        {
            earr1[s1[i]-'a']++;
            earr2[s2[i]-'a']++;
        }
        else
        {
            oarr1[s1[i]-'a']++;
            oarr2[s2[i]-'a']++;
        }
    }
    for(int i=0;i<26;i++)
    {
        if(earr1[i] != earr2[i] || oarr1[i] != oarr2[i])
        {
            return false;
        }
    }
    return true;
}

void soln()
{
    vector<pair<string,string>> testSet{
        {"abcdba", "cabdab"},
        {"abe", "bea"},
        {"", ""},
    };
    for(int i=0;i<testSet.size();++i){
        
        auto start = high_resolution_clock::now();
        cout << checkStrings(testSet[i].first, testSet[i].second)<< endl;
        auto stop = high_resolution_clock::now();
        auto duration = duration_cast<milliseconds>(stop - start);
        cout << "Time taken: " << duration.count() << " ms" << endl;
    }
}


int main(){
    ios_base::sync_with_stdio(false);

    soln();
    return 0;
}